'use strict';
/**
 * SMOKE — FRG-184
 * Verifies the sim page loads, Phaser boots, and all 3 characters are present.
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, getEngineState } = require('../helpers');

test.describe('Smoke: App loads and sim initialises', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await waitForEngine(page);
  });

  test('page title is correct', async ({ page }) => {
    await expect(page).toHaveTitle(/AI Aquarium/i);
  });

  test('Phaser canvas renders', async ({ page }) => {
    const canvas = page.locator('canvas');
    await expect(canvas).toBeVisible();
  });

  test('sim clock is visible and ticking', async ({ page }) => {
    // Clock text is rendered by Phaser into the canvas — read via engine
    const state1 = await getEngineState(page);
    expect(state1.simTime).toMatch(/^\d+:\d{2} (AM|PM)$/);

    // Verify via raw simTimeMs (more precise than string comparison)
    // simSpeed = 60 → 1 real second = 60 sim seconds
    const ms0 = await page.evaluate(() => window._gameEngine.simTimeMs);
    // Wait 5 s → expect ~300 sim seconds (5 real min) of advancement
    await page.waitForTimeout(5000);
    const ms1 = await page.evaluate(() => window._gameEngine.simTimeMs);

    expect(ms1, 'simTimeMs did not advance — Phaser update loop may not be running').toBeGreaterThan(ms0);
  });

  test('exactly 3 characters are loaded', async ({ page }) => {
    const state = await getEngineState(page);
    expect(state.characters).toHaveLength(3);
  });

  test('characters have expected names', async ({ page }) => {
    const state = await getEngineState(page);
    const labels = state.characters.map(c => c.label).sort();
    expect(labels).toEqual(['Maple', 'Nyx', 'Sol']);
  });

  test('AI engine is enabled', async ({ page }) => {
    const state = await getEngineState(page);
    expect(state.aiEnabled).toBe(true);
  });

  test('all 10 interactive objects are loaded', async ({ page }) => {
    const state = await getEngineState(page);
    expect(state.objectStates).toHaveLength(10);
    const ids = state.objectStates.map(o => o.id).sort();
    expect(ids).toEqual([
      'bed', 'bonsai', 'bookshelf', 'desk', 'easel',
      'fridge', 'kotatsu', 'stove', 'tea_set', 'tv',
    ]);
  });

  test('debug panel opens and shows object states', async ({ page }) => {
    const debugBtn = page.getByRole('button', { name: /debug/i });
    await expect(debugBtn).toBeVisible();
    await debugBtn.click();
    await expect(page.getByText('OBJECT STATES')).toBeVisible();
    await expect(page.getByText('Stove')).toBeVisible();
  });
});

