'use strict';
/**
 * REGRESSION — FRG-209
 * M1 Test Plan: Debug Dashboard (/debug.html)
 *
 * Tests the full debug dashboard which is the M1 foundation.
 * The debug page runs the sim engine headlessly and provides real-time visibility
 * into: character states, object states, and the event log.
 *
 * Target: /debug.html (not the main Phaser page — that is M2).
 */
const { test, expect } = require('@playwright/test');

/** Wait for the debug dashboard to finish loading (objects + characters grid populated). */
async function waitForDashboard(page, timeout = 20_000) {
  await page.waitForSelector('#characters-grid', { timeout });
  await page.waitForSelector('#event-log', { timeout });
  // Wait until at least one character card renders an action value
  await page.waitForFunction(
    () => {
      const cards = document.querySelectorAll('[id^="char-"]');
      if (cards.length < 3) return false;
      // Check that character cards have content
      return cards[0].textContent.includes('Action');
    },
    { timeout }
  );
}

test.describe('M1: Debug Dashboard — /debug.html', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/debug.html');
    await waitForDashboard(page);
  });

  // ── LAYOUT ────────────────────────────────────────────────────────────────

  test('debug dashboard has correct page title', async ({ page }) => {
    await expect(page).toHaveTitle(/AI Aquarium.*Debug/i);
  });

  test('OBJECTS section shows all 10 interactive objects', async ({ page }) => {
    const objectIds = [
      'stove', 'fridge', 'tea_set', 'kotatsu', 'tv',
      'bookshelf', 'desk', 'bed', 'easel', 'bonsai',
    ];
    for (const id of objectIds) {
      await expect(page.locator(`#obj-${id}`)).toBeVisible();
    }
  });

  test('CHARACTERS section shows 3 character cards', async ({ page }) => {
    await expect(page.locator('#char-0')).toBeVisible();
    await expect(page.locator('#char-1')).toBeVisible();
    await expect(page.locator('#char-2')).toBeVisible();
  });

  test('character cards show Maple, Sol, and Nyx', async ({ page }) => {
    const names = await page.evaluate(() =>
      ['char-0', 'char-1', 'char-2'].map(id => {
        const card = document.getElementById(id);
        return card ? card.textContent.match(/(Maple|Sol|Nyx)/)?.[1] ?? null : null;
      })
    );
    expect(names).toContain('Maple');
    expect(names).toContain('Sol');
    expect(names).toContain('Nyx');
  });

  test('character cards display Action, Mood, and Energy fields', async ({ page }) => {
    const card0Text = await page.locator('#char-0').innerText();
    expect(card0Text).toMatch(/Action/i);
    expect(card0Text).toMatch(/Mood/i);
    expect(card0Text).toMatch(/Energy/i);
  });

  test('character Mood and Energy start at 100', async ({ page }) => {
    for (const id of ['char-0', 'char-1', 'char-2']) {
      const text = await page.locator(`#${id}`).innerText();
      const moodMatch = text.match(/Mood\s+(\d+)/i);
      const energyMatch = text.match(/Energy\s+(\d+)/i);
      expect(moodMatch, `${id}: Mood not found`).toBeTruthy();
      expect(energyMatch, `${id}: Energy not found`).toBeTruthy();
      expect(parseInt(moodMatch[1]), `${id}: Mood should be 100`).toBe(100);
      expect(parseInt(energyMatch[1]), `${id}: Energy should be 100`).toBe(100);
    }
  });

  test('EVENT LOG section is present', async ({ page }) => {
    await expect(page.locator('#log-section')).toBeVisible();
    await expect(page.locator('#event-log')).toBeVisible();
  });

  test('sim clock is visible and shows AM/PM time', async ({ page }) => {
    const clockText = await page.locator('#clock').innerText();
    expect(clockText).toMatch(/\d+:\d{2} (AM|PM)/);
  });

  test('Pause and Reset controls are visible', async ({ page }) => {
    await expect(page.locator('#btn-pause')).toBeVisible();
    await expect(page.locator('#btn-reset')).toBeVisible();
  });

  test('speed buttons (1x, 2x, 4x) are present', async ({ page }) => {
    await expect(page.getByRole('button', { name: '1x' })).toBeVisible();
    await expect(page.getByRole('button', { name: '2x' })).toBeVisible();
    await expect(page.getByRole('button', { name: '4x' })).toBeVisible();
  });

  // ── REAL-TIME UPDATES ─────────────────────────────────────────────────────

  test('sim clock advances over real time', async ({ page }) => {
    const time1 = await page.locator('#clock').innerText();
    await page.waitForTimeout(5000);
    const time2 = await page.locator('#clock').innerText();
    expect(time2, 'Sim clock did not advance — sim may be frozen').not.toBe(time1);
  });

  test('event log populates with AI decision entries within 15 seconds', async ({ page }) => {
    // Wait for at least one AI event in the log
    await page.waitForFunction(
      () => {
        const log = document.getElementById('event-log');
        return log && log.textContent.includes('AI');
      },
      { timeout: 15_000 }
    );
    const logText = await page.locator('#event-log').innerText();
    expect(logText).toMatch(/AI/);
  });

  test('event log entries include character name and interaction target', async ({ page }) => {
    // Wait for AI events
    await page.waitForFunction(
      () => {
        const log = document.getElementById('event-log');
        return log && (log.textContent.match(/AI/g) || []).length >= 1;
      },
      { timeout: 15_000 }
    );
    const logText = await page.locator('#event-log').innerText();
    // At least one entry should mention a character name
    const hasCharName = /(Maple|Sol|Nyx)/.test(logText);
    expect(hasCharName, 'Event log should mention a character name').toBe(true);
  });

  test('event log entries include object state transitions (auto events)', async ({ page }) => {
    test.setTimeout(90_000);
    // Wait for an auto object state transition to appear in the log
    await page.waitForFunction(
      () => {
        const log = document.getElementById('event-log');
        return log && log.textContent.includes('auto');
      },
      { timeout: 75_000, polling: 1000 }
    );
    const logText = await page.locator('#event-log').innerText();
    expect(logText).toMatch(/auto/);
    // Should show idle → something transition
    expect(logText).toMatch(/idle|brewing|cooking|tending|reading|watching|sleeping|working|painting/i);
  });

  test('object badge updates from idle to active when triggered', async ({ page }) => {
    // Trigger bonsai via use button
    const useBtn = page.locator('#int-bonsai button');
    const bonsaiBadge = page.locator('#badge-bonsai');

    // Confirm starts idle
    await expect(bonsaiBadge).toHaveText('idle');
    await useBtn.click();

    // Badge should change from idle
    await expect(bonsaiBadge).not.toHaveText('idle', { timeout: 5000 });
    const newState = await bonsaiBadge.innerText();
    expect(newState).not.toBe('idle');
    console.log(`Bonsai transitioned to: ${newState}`);
  });

  test('active object shows timer countdown text ("Xs remaining")', async ({ page }) => {
    test.setTimeout(90_000);
    // Wait for any object to show a timer
    await page.waitForFunction(
      () => {
        const timerTexts = document.querySelectorAll('[id^="timertext-"]');
        return Array.from(timerTexts).some(el => el.textContent.includes('remaining'));
      },
      { timeout: 75_000, polling: 1000 }
    );
    const timerTexts = await page.evaluate(() =>
      Array.from(document.querySelectorAll('[id^="timertext-"]'))
        .filter(el => el.textContent.includes('remaining'))
        .map(el => ({ id: el.id, text: el.textContent }))
    );
    expect(timerTexts.length).toBeGreaterThan(0);
    console.log('Active object timers:', timerTexts);
  });

  test('character card shows "Hold Xs" when character is interacting', async ({ page }) => {
    test.setTimeout(90_000);
    // Wait for a character to show Hold text (means they are actively interacting)
    await page.waitForFunction(
      () => {
        const cards = document.querySelectorAll('[id^="char-"]');
        return Array.from(cards).some(c => /Hold\s+\d+s/.test(c.textContent));
      },
      { timeout: 75_000, polling: 1000 }
    );
    const holdCards = await page.evaluate(() =>
      Array.from(document.querySelectorAll('[id^="char-"]'))
        .filter(c => /Hold\s+\d+s/.test(c.textContent))
        .map(c => {
          const nameMatch = c.textContent.match(/(Maple|Sol|Nyx)/);
          const holdMatch = c.textContent.match(/Hold\s+(\d+)s/);
          return {
            name: nameMatch?.[1],
            hold: holdMatch?.[1] ? parseInt(holdMatch[1]) : null,
          };
        })
    );
    expect(holdCards.length).toBeGreaterThan(0);
    for (const card of holdCards) {
      expect(card.hold, `${card.name}: Hold duration should be > 0`).toBeGreaterThan(0);
    }
    console.log('Interacting characters:', holdCards);
  });

  test('character card shows "AI next Xs" countdown for upcoming decision', async ({ page }) => {
    const aiNextText = await page.waitForFunction(
      () => {
        const cards = document.querySelectorAll('[id^="char-"]');
        return Array.from(cards).some(c => /AI next\s+\d+s/.test(c.textContent));
      },
      { timeout: 15_000 }
    );
    const cards = await page.evaluate(() =>
      Array.from(document.querySelectorAll('[id^="char-"]'))
        .map(c => ({
          id: c.id,
          aiNext: c.textContent.match(/AI next\s+(\d+)s/)?.[1] ?? null,
        }))
    );
    const withAiNext = cards.filter(c => c.aiNext !== null);
    expect(withAiNext.length).toBeGreaterThan(0);
    for (const c of withAiNext) {
      const seconds = parseInt(c.aiNext);
      expect(seconds, `${c.id}: AI next should be ≤ 30s`).toBeLessThanOrEqual(30);
    }
    console.log('AI next countdown:', withAiNext);
  });

  // ── PAUSE / RESUME ────────────────────────────────────────────────────────

  test('Pause button stops the sim clock', async ({ page }) => {
    const time1 = await page.locator('#clock').innerText();
    await page.locator('#btn-pause').click();
    await page.waitForTimeout(3000);
    const time2 = await page.locator('#clock').innerText();
    expect(time2, 'Clock should be frozen when paused').toBe(time1);
    // Resume
    await page.locator('#btn-pause').click();
    await page.waitForTimeout(2000);
    const time3 = await page.locator('#clock').innerText();
    expect(time3, 'Clock should advance after resume').not.toBe(time2);
  });
});

