'use strict';
/**
 * REGRESSION — FRG-234
 * Smart Objects — Slot System
 *
 * Verifies the slot/capacity system described in the M1 spec:
 *  - Every object has a #slots-{id} element with pip indicators
 *  - Capacity-1 objects (most): 1 pip, shows "1/1 free"
 *  - Multi-capacity objects (kotatsu, tv): 2 pips, shows "2/2 free"
 *  - Slot state changes: available → reserved (character walking toward) → occupied (character using)
 *  - When at capacity, label shows "full"
 *
 * Target: /debug.html
 */
const { test, expect } = require('@playwright/test');

async function waitForDashboard(page, timeout = 20_000) {
  await page.waitForSelector('#characters-grid', { timeout });
  await page.waitForFunction(
    () => {
      const cards = document.querySelectorAll('[id^="char-"]');
      return cards.length >= 3 && cards[0].textContent.includes('Action');
    },
    { timeout }
  );
}

test.describe('M1: Smart Objects — Slot System', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/debug.html');
    await waitForDashboard(page);
  });

  // ── CAPACITY DISPLAY ────────────────────────────────────────────────────────

  test('all 10 objects have a slot-info element in the debug UI', async ({ page }) => {
    const objectIds = [
      'tea_set', 'kotatsu', 'stove', 'bonsai', 'fridge',
      'bed', 'bookshelf', 'desk', 'easel', 'tv',
    ];
    for (const id of objectIds) {
      const slotEl = page.locator(`#slots-${id}`);
      await expect(slotEl, `#slots-${id} should be visible`).toBeVisible();
    }
  });

  test('all 10 objects show pip indicators', async ({ page }) => {
    const objectIds = [
      'tea_set', 'kotatsu', 'stove', 'bonsai', 'fridge',
      'bed', 'bookshelf', 'desk', 'easel', 'tv',
    ];
    for (const id of objectIds) {
      const pips = page.locator(`#slots-${id} .slot-pip`);
      const count = await pips.count();
      expect(count, `${id}: expected at least 1 pip indicator`).toBeGreaterThanOrEqual(1);
    }
  });

  test('capacity-1 objects show 1 pip each', async ({ page }) => {
    const singleCapObjects = ['tea_set', 'stove', 'bonsai', 'fridge', 'bed', 'bookshelf', 'desk', 'easel'];
    for (const id of singleCapObjects) {
      const pips = page.locator(`#slots-${id} .slot-pip`);
      const count = await pips.count();
      expect(count, `${id}: expected 1 pip (capacity=1)`).toBe(1);
    }
  });

  test('kotatsu has 2 pips (capacity=2)', async ({ page }) => {
    const pips = page.locator('#slots-kotatsu .slot-pip');
    const count = await pips.count();
    expect(count, 'kotatsu: expected 2 pips (capacity=2)').toBe(2);
  });

  test('tv has 2 pips (capacity=2)', async ({ page }) => {
    const pips = page.locator('#slots-tv .slot-pip');
    const count = await pips.count();
    expect(count, 'tv: expected 2 pips (capacity=2)').toBe(2);
  });

  test('slot labels show "N/N free" format for available objects', async ({ page }) => {
    // At page load most objects should be free
    const labels = await page.evaluate(() => {
      const ids = ['kotatsu', 'stove', 'fridge', 'bed', 'bookshelf', 'desk', 'easel', 'tv'];
      return ids.map(id => {
        const el = document.querySelector(`#slots-${id} .slot-label`);
        return { id, text: el ? el.textContent.trim() : null };
      });
    });

    for (const { id, text } of labels) {
      expect(text, `${id}: slot label should exist`).toBeTruthy();
      // Acceptable: "N/N free" OR "full" (if already taken at load time)
      const isValidLabel = /^\d+\/\d+ free$/.test(text) || text === 'full';
      expect(isValidLabel, `${id}: unexpected slot label "${text}"`).toBe(true);
    }
    console.log('Slot labels:', labels.map(l => `${l.id}: ${l.text}`).join(', '));
  });

  test('kotatsu slot label shows "2/2 free" when unoccupied', async ({ page }) => {
    // Verify the kotatsu starts with both slots available
    const label = await page.locator('#slots-kotatsu .slot-label').innerText();
    // It may already be reserved/occupied, so just verify it is a valid format
    expect(label).toMatch(/^(\d\/\d free|full)$/);
    console.log('Kotatsu slot label:', label);
  });

  // ── SLOT STATE CHANGES ──────────────────────────────────────────────────────

  test('slot pip changes to reserved when a character walks toward the object', async ({ page }) => {
    test.setTimeout(90_000);

    // Poll until at least one object has a reserved pip
    await page.waitForFunction(
      () => document.querySelectorAll('.slot-pip.reserved').length > 0,
      { timeout: 75_000, polling: 1000 }
    );

    const reservedInfo = await page.evaluate(() => {
      const pips = document.querySelectorAll('.slot-pip.reserved');
      return Array.from(pips).map(pip => ({
        title: pip.getAttribute('title'),
        parentId: pip.closest('[id^="slots-"]')?.id,
      }));
    });

    expect(reservedInfo.length).toBeGreaterThan(0);
    // Title should include "heading here" text
    for (const info of reservedInfo) {
      expect(info.title, 'Reserved pip should have character info in title').toMatch(/heading here/);
    }
    console.log('Reserved slot pips:', reservedInfo);
  });

  test('object shows "full" label when all slots are occupied or reserved', async ({ page }) => {
    test.setTimeout(90_000);

    // Poll until at least one object shows "full" in slot label
    await page.waitForFunction(
      () => {
        const labels = document.querySelectorAll('.slot-label.full');
        return labels.length > 0;
      },
      { timeout: 75_000, polling: 1000 }
    );

    const fullObjects = await page.evaluate(() => {
      const labels = document.querySelectorAll('.slot-label.full');
      return Array.from(labels).map(el => ({
        slotId: el.closest('[id^="slots-"]')?.id,
        label: el.textContent.trim(),
      }));
    });

    expect(fullObjects.length).toBeGreaterThan(0);
    for (const obj of fullObjects) {
      expect(obj.label).toBe('full');
    }
    console.log('Full objects:', fullObjects);
  });

  // ── BLOCKING BEHAVIOR ────────────────────────────────────────────────────────

  test('single-capacity object pip becomes reserved when character heads there', async ({ page }) => {
    test.setTimeout(60_000);

    // Single-capacity object IDs
    const singleCapIds = ['tea_set', 'stove', 'bonsai', 'fridge', 'bed', 'bookshelf', 'desk', 'easel'];

    // Wait for any single-capacity object to be reserved
    await page.waitForFunction(
      (ids) => ids.some(id => {
        const el = document.getElementById('slots-' + id);
        return el && el.querySelector('.slot-pip.reserved') !== null;
      }),
      singleCapIds,
      { timeout: 45_000, polling: 500 }
    );

    const reservedSingle = await page.evaluate((ids) =>
      ids.filter(id => {
        const el = document.getElementById('slots-' + id);
        return el && el.querySelector('.slot-pip.reserved') !== null;
      }),
      singleCapIds
    );

    expect(reservedSingle.length).toBeGreaterThan(0);
    console.log('Single-cap objects with reserved slot:', reservedSingle);
  });
});

