    page.on('response', async res => {
      if (res.url().includes('/api/llm') && res.request().method() === 'POST') {
        try {
          const json = await res.json();
          const text = json?.content?.[0]?.text ?? json?.choices?.[0]?.message?.content;
          if (text) responses.push(JSON.parse(text));
        } catch { /* ignore malformed */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);
    await page.waitForTimeout(10_000);

    expect(responses.length, 'Should have captured at least 3 LLM decisions').toBeGreaterThanOrEqual(3);

    // Every response must have a string dialogue field (drives speech bubbles)
    // and a string description field (drives event log narrative)
    for (const decision of responses) {
      expect(decision, 'LLM decision should include dialogue field').toHaveProperty('dialogue');
      expect(typeof decision.dialogue, `dialogue should be a string, got ${typeof decision.dialogue}`).toBe('string');
      expect(decision.dialogue.length, 'dialogue should not be empty').toBeGreaterThan(0);

      expect(decision, 'LLM decision should include description field').toHaveProperty('description');
      expect(typeof decision.description, `description should be a string, got ${typeof decision.description}`).toBe('string');
      expect(decision.description.length, 'description should not be empty').toBeGreaterThan(0);
    }

    const actionBreakdown = responses.reduce((acc, r) => {
      acc[r.action] = (acc[r.action] || 0) + 1;
      return acc;
    }, {});
    console.log('LLM responses — action breakdown:', actionBreakdown);
    console.log('Sample dialogue:', responses[0]?.dialogue);
    console.log('Sample description:', responses[0]?.description);
  });
});

