  // ── MULTI-CAPACITY SIMULTANEOUS USE ──────────────────────────────────────

  test('multi-capacity object (kotatsu or tv) shows both slots occupied simultaneously', async ({ page }) => {
    // Spec: "two characters can use kotatsu/tv simultaneously"
    // This is probabilistic — the AI must direct two characters to the same object.
    // We observe and verify; gracefully skip if not observed in this run.
    test.setTimeout(120_000);

    const multiCapIds = ['kotatsu', 'tv'];

    const foundMultiOccupied = await page.waitForFunction(
      (ids) => {
        for (const id of ids) {
          const el = document.getElementById('slots-' + id);
          if (!el) continue;
          const pips = el.querySelectorAll('.slot-pip');
          // Both pips non-free (reserved or occupied)
          const nonFree = Array.from(pips).filter(p => !p.classList.contains('free'));
          if (nonFree.length >= 2) return true;
          // Or the label explicitly shows "full" (all slots taken)
          const label = el.querySelector('.slot-label');
          if (label && label.textContent.trim() === 'full') return true;
        }
        return false;
      },
      multiCapIds,
      { timeout: 90_000, polling: 1000 }
    ).catch(() => null);

    if (!foundMultiOccupied) {
      console.log('[INFO] Multi-capacity simultaneous occupation not observed in this run. ' +
        'AI must direct two characters to the same kotatsu or tv — non-deterministic.');
      return;
    }

    // Verify the multi-cap object state
    const state = await page.evaluate((ids) =>
      ids.map(id => {
        const el = document.getElementById('slots-' + id);
        if (!el) return { id, error: 'element not found' };
        const pips = el.querySelectorAll('.slot-pip');
        const label = el.querySelector('.slot-label');
        return {
          id,
          totalPips: pips.length,
          nonFreePips: Array.from(pips).filter(p => !p.classList.contains('free')).length,
          label: label?.textContent.trim() ?? null,
        };
      }),
      multiCapIds
    );

    const fullyOccupied = state.filter(o => o.nonFreePips >= 2 || o.label === 'full');
    expect(fullyOccupied.length, 'At least one multi-cap object should show both slots taken').toBeGreaterThan(0);
    // Multi-cap objects should have 2 pips
    for (const obj of fullyOccupied) {
      expect(obj.totalPips, `${obj.id} should have 2 pips (capacity=2)`).toBe(2);
    }
    console.log('Multi-capacity objects with both slots occupied:', fullyOccupied);
  });
});

