test('Reset button clears event log and restores sim to initial state', async ({ page }) => {
  test.setTimeout(90_000);

  // Wait for event log to accumulate enough entries to clearly measure before/after.
  // The sim fires AI decisions quickly, so we expect ≥5 entries within 30s.
  await page.waitForFunction(
    () => {
      const log = document.getElementById('event-log');
      return log && log.querySelectorAll('.log-entry').length >= 5;
    },
    { timeout: 30_000 }
  );

  const countBefore = await page.evaluate(
    () => document.getElementById('event-log')?.querySelectorAll('.log-entry').length ?? 0
  );
  expect(countBefore, 'Event log should have ≥5 entries before reset').toBeGreaterThanOrEqual(5);

  // Also record the sim clock time before reset
  const clockBefore = await page.locator('#clock').innerText();
  const minsBefore = parseSimMinutes(clockBefore);

  // Click Reset
  await page.locator('#btn-reset').click();
  // Give the UI a moment to apply the reset and fire any immediate new events
  await page.waitForTimeout(1000);

  // Event log should have significantly fewer entries than before reset.
  // The new sim may fire 1-2 initial events immediately, so allow a small buffer.
  const countAfter = await page.evaluate(
    () => document.getElementById('event-log')?.querySelectorAll('.log-entry').length ?? 0
  );
  expect(
    countAfter,
    `Event log after reset (${countAfter}) should be much less than before (${countBefore})`
  ).toBeLessThan(Math.ceil(countBefore / 2));

  // Clock should have reset to an earlier time (start of the sim day)
  const clockAfter = await page.locator('#clock').innerText();
  expect(clockAfter).toMatch(/\d+:\d{2} (AM|PM)/);
  const minsAfter = parseSimMinutes(clockAfter);
  expect(
    minsAfter,
    `Clock (${clockAfter}) should show an earlier time than before reset (${clockBefore})`
  ).toBeLessThan(minsBefore);

  // Sim should continue running after reset (clock advances again)
  await page.waitForTimeout(4000);
  const clockAdvanced = await page.locator('#clock').innerText();
  expect(clockAdvanced, 'Clock should advance after reset').not.toBe(clockAfter);
});

