'use strict';
/**
 * REGRESSION — FRG-209
 * M1 Test Plan: Activity Duration & 30s AI Cycle
 *
 * Verifies:
 *  1. Characters stay at objects for the correct activity duration
 *  2. interactTimerMax matches known object durations
 *  3. AI decision interval is configured to 30s
 *  4. Characters cycle through walk→interact→idle→walk
 *
 * Tests against the main page (which exposes window._gameEngine).
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, getEngineState, pollEngineState } = require('../helpers');

test.describe('M1: Activity Duration & 30s AI Cycle', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await waitForEngine(page);
  });

  // ── AI CYCLE ──────────────────────────────────────────────────────────────

  test('AI decisionIntervalMs is configured to 30 seconds', async ({ page }) => {
    const intervalMs = await page.evaluate(() =>
      window._gameEngine.aiEngine.decisionIntervalMs
    );
    expect(intervalMs, 'AI decision interval must be 30000ms (30s)').toBe(30_000);
  });

  test('AI timer object is initialized (keyed per character)', async ({ page }) => {
    // _timers is an object keyed by character name; verify it exists as an object
    const timersIsObject = await page.evaluate(() => {
      const timers = window._gameEngine.aiEngine._timers;
      return timers !== null && typeof timers === 'object' && !Array.isArray(timers);
    });
    expect(timersIsObject, 'aiEngine._timers should be an object').toBe(true);
  });

  test('second AI decision round fires after characters finish interacting', async ({ page }) => {
    // This test does its own goto so the interceptor captures ALL requests from page load.
    test.setTimeout(120_000);

    const requestTimestamps = [];
    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        requestTimestamps.push(Date.now());
      }
    });

    // Navigate AFTER setting up the interceptor
    await page.goto('/');
    await waitForEngine(page);

    // Wait for first batch (all 3 chars fire within ~5s of load)
    await page.waitForTimeout(8_000);

    const firstBatch = requestTimestamps.length;
    expect(firstBatch, 'First batch: all 3 characters should have fired').toBeGreaterThanOrEqual(3);

    // Wait for characters to finish interacting (up to 60s) + 30s cycle interval
    // Total: up to 90s real time for second batch
    await page.waitForTimeout(90_000);

    const totalRequests = requestTimestamps.length;
    const secondBatch = totalRequests - firstBatch;
    expect(secondBatch, 'Second AI decision batch should have fired for at least 1 character').toBeGreaterThanOrEqual(1);

    if (secondBatch >= 1) {
      const lastFirst = requestTimestamps[firstBatch - 1];
      const firstSecond = requestTimestamps[firstBatch];
      const gapMs = firstSecond - lastFirst;
      console.log(`AI cycle gap between rounds: ${(gapMs / 1000).toFixed(1)}s (interval = 30s)`);
    }
    console.log(`Total LLM requests in ~100s: ${totalRequests} (first: ${firstBatch}, second: ${secondBatch})`);
  });

  // ── ACTIVITY DURATION ────────────────────────────────────────────────────

  test('character stays in interacting state for expected duration', async ({ page }) => {
    test.setTimeout(120_000);

    // Wait for a character to start interacting
    const startState = await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'interacting'),
      20_000
    );
    const interactingChar = startState.characters.find(c => c.action === 'interacting');
    expect(interactingChar, 'Expected at least one character to be interacting').toBeTruthy();

    // Record entry time and check interactTimerMax
    const timerInfo = await page.evaluate(name => {
      const char = window._gameEngine.characters.find(c => c.label === name);
      return {
        label: char.label,
        interactTimer: char.interactTimer,
        interactTimerMax: char.interactTimerMax,
        action: char.action,
      };
    }, interactingChar.label);

    console.log(`${timerInfo.label} interactTimerMax: ${timerInfo.interactTimerMax}ms`);
    expect(timerInfo.interactTimerMax, 'interactTimerMax should be > 0').toBeGreaterThan(0);

    // Verify character stays interacting for at least half the remaining duration
    // (we don't wait the full duration to keep test fast)
    const halfRemaining = Math.min((timerInfo.interactTimerMax - timerInfo.interactTimer) / 2, 8000);
    await page.waitForTimeout(halfRemaining);

    const midState = await page.evaluate(name => {
      const char = window._gameEngine.characters.find(c => c.label === name);
      return { label: char.label, action: char.action };
    }, interactingChar.label);

    expect(midState.action, `${midState.label} should still be interacting mid-activity`)
      .toBe('interacting');
  });

  test('interactTimerMax values fall within expected object duration ranges', async ({ page }) => {
    test.setTimeout(60_000);

    // Wait for at least one character to interact
    await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'interacting'),
      20_000
    );

    const timerValues = await page.evaluate(() =>
      window._gameEngine.characters
        .filter(c => c.action === 'interacting')
        .map(c => ({
          label: c.label,
          interactTimerMax: c.interactTimerMax,
        }))
    );

    for (const { label, interactTimerMax } of timerValues) {
      // Known activity durations range from ~12s (bonsai) to ~60s (bed)
      // All durations should be reasonable: 5s–120s
      expect(interactTimerMax, `${label}: duration out of expected range (5s–120s)`)
        .toBeGreaterThanOrEqual(5_000);
      expect(interactTimerMax, `${label}: duration out of expected range (5s–120s)`)
        .toBeLessThanOrEqual(120_000);
      console.log(`${label}: interactTimerMax = ${interactTimerMax / 1000}s`);
    }
  });

  test('activity timer resets after completion (character cycles through activities)', async ({ page }) => {
    test.setTimeout(120_000);

    // Wait for a character to start interacting
    await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'interacting'),
      20_000
    );

    // Find a character who is interacting with time remaining
    const initial = await page.evaluate(() =>
      window._gameEngine.characters
        .filter(c => c.action === 'interacting')
        .map(c => ({
          label: c.label,
          interactTimer: c.interactTimer,
          interactTimerMax: c.interactTimerMax,
          remaining: c.interactTimerMax - c.interactTimer,
        }))
        .sort((a, b) => a.remaining - b.remaining)
    );

    if (initial.length === 0) {
      console.log('No interacting characters found, skipping');
      return;
    }

    const target = initial[0];
    const waitMs = Math.min(target.remaining + 5000, 30_000);
    console.log(`Tracking ${target.label}: ${target.remaining}ms remaining, waiting ${waitMs}ms...`);

    await page.waitForTimeout(waitMs);

    // After waiting, verify the character's timer has reset (interactTimer < original interactTimerMax)
    // This confirms the activity completed and a new cycle began
    const after = await page.evaluate(label => {
      const c = window._gameEngine.characters.find(c => c.label === label);
      return {
        label: c.label,
        action: c.action,
        interactTimer: c.interactTimer,
        interactTimerMax: c.interactTimerMax,
      };
    }, target.label);

    console.log(`${target.label} after activity:`, JSON.stringify(after, null, 2));

    // The timer must have moved — either:
    // a) reset (new activity started: interactTimer < original timer value), OR
    // b) character is idle/walking (left interacting state)
    if (after.action === 'interacting') {
      // If still interacting, the timer must have reset (new cycle)
      expect(after.interactTimer, `${target.label}: activity timer should have reset`)
        .toBeLessThan(target.interactTimer + 1000); // timer reset means lower than original
    } else {
      // Left interacting state — that's also valid
      expect(['idle', 'walking']).toContain(after.action);
    }
  });

  // ── ACTION TYPE COVERAGE ─────────────────────────────────────────────────

  test('idle action type is observed on characters', async ({ page }) => {
    // Engine starts with characters in idle (before first decision)
    const initialState = await getEngineState(page);
    const idleChars = initialState.characters.filter(c => c.action === 'idle');
    // At start at least some characters should be idle or walking
    const hasIdleOrWalking = initialState.characters.some(
      c => c.action === 'idle' || c.action === 'walking'
    );
    expect(hasIdleOrWalking, 'Characters should start in idle or walking state').toBe(true);
  });

  test('walking action type is observed within 15 seconds', async ({ page }) => {
    const state = await pollEngineState(
      page,
      s => s.characters.some(c => c.action === 'walking'),
      15_000
    );
    expect(state.characters.some(c => c.action === 'walking')).toBe(true);
  });

  test('interacting action type is observed within 30 seconds', async ({ page }) => {
    const state = await pollEngineState(
      page,
      s => s.characters.some(c => c.action === 'interacting'),
      30_000
    );
    expect(state.characters.some(c => c.action === 'interacting')).toBe(true);
  });

  test('LLM response action field contains only valid action types', async ({ page }) => {
    const decisions = [];

    page.on('response', async res => {
      if (res.url().includes('/api/llm') && res.request().method() === 'POST') {
        try {
          const json = await res.json();
          const text = json?.content?.[0]?.text ?? json?.choices?.[0]?.message?.content;
          if (text) decisions.push(JSON.parse(text));
        } catch { /* ignore */ }
      }
    });

    await page.waitForTimeout(10_000);

    expect(decisions.length, 'No LLM decisions received').toBeGreaterThanOrEqual(3);
    const validActions = ['move', 'interact', 'idle', 'talk'];
    for (const d of decisions) {
      expect(validActions, `Unexpected action: ${d.action}`).toContain(d.action);
    }
    const actionTypes = [...new Set(decisions.map(d => d.action))];
    console.log('Action types seen in LLM responses:', actionTypes);
  });
});
